import sqlite3
from typing import Dict, List

# Database schema:
class User:
    def __init__(self, username: str):
        self.username = username
        self.access_level = 0  # 0: read only, 1: read & write

class File:
    def __init__(self, filename: str, owner_username: str, access_level_required: int):
        self.filename = filename
        self.owner_username = owner_username
        self.access_level_required = access_level_required

# Database interface
class DBInterface:
    def __init__(self, db_name: str):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def add_user(self, user: User) -> None:
        self.cursor.execute("INSERT INTO users (username, access_level) VALUES (?, ?)", (user.username, user.access_level))
        self.conn.commit()

    def get_access_level(self, username: str) -> int:
        self.cursor.execute("SELECT access_level FROM users WHERE username = ?", (username,))
        return self.cursor.fetchone()[0]

    def add_file(self, file: File) -> None:
        self.cursor.execute("INSERT INTO files (filename, owner_username, access_level_required) VALUES (?, ?, ?)", 
                            (file.filename, file.owner_username, file.access_level_required))
        self.conn.commit()

# File access control system
class FileAccessControlSystem:
    def __init__(self, db_interface: DBInterface):
        self.db_interface = db_interface

    def is_permitted(self, user: User, file: File) -> bool:
        if self.db_interface.get_access_level(user.username) >= file.access_level_required:
            return True
        else:
            return False

    def read_file(self, filename: str, user: User) -> List[str]:
        if self.is_permitted(user, File(filename, 'None', 0)):  # assume default access level is 0 (read only)
            try:
                with open(filename, 'r') as f:
                    return f.read().splitlines()
            except FileNotFoundError:
                print(f"File {filename} not found.")
                return []
        else:
            print("User does not have permission to read file.")
            return []

